// ==================== 本地缓存模块 ====================
// 使用 localStorage 实现 TTL 缓存，减少 API 调用

const CACHE_PREFIX = 'cw_cache_';

// TTL 配置
const PROJECT_LIST_TTL = 5 * 60 * 1000;    // 项目列表缓存 5 分钟
const ITEM_CONTENT_TTL = 30 * 60 * 1000;   // 项目内容缓存 30 分钟
const REGEX_CONTENT_TTL = 30 * 60 * 1000;  // 正则内容缓存 30 分钟

// 缓存 key 常量
const KEY_PROJECT_LIST = `${CACHE_PREFIX}project_list`;
const KEY_ITEM_CONTENT_PREFIX = `${CACHE_PREFIX}item_content_`;
const KEY_REGEX_CONTENT_PREFIX = `${CACHE_PREFIX}regex_content_`;

interface CacheEntry<T> {
  data: T;
  timestamp: number;
  ttl: number;
}

// ==================== 通用缓存操作 ====================

/** 读取缓存，如果过期或不存在则返回 null */
function getCache<T>(key: string): T | null {
  try {
    const raw = localStorage.getItem(key);
    if (!raw) return null;

    const entry: CacheEntry<T> = JSON.parse(raw);
    const now = Date.now();

    if (now - entry.timestamp > entry.ttl) {
      // 缓存已过期，移除
      localStorage.removeItem(key);
      console.info(`[Cache] 缓存过期: ${key}`);
      return null;
    }

    console.info(`[Cache] 命中: ${key}`);
    return entry.data;
  } catch (e) {
    // 解析失败，移除损坏的缓存
    localStorage.removeItem(key);
    return null;
  }
}

/** 写入缓存 */
function setCache<T>(key: string, data: T, ttl: number): void {
  try {
    const entry: CacheEntry<T> = {
      data,
      timestamp: Date.now(),
      ttl,
    };
    localStorage.setItem(key, JSON.stringify(entry));
    console.info(`[Cache] 写入: ${key}`);
  } catch (e) {
    // localStorage 可能已满，忽略
    console.warn(`[Cache] 写入失败: ${key}`, e);
  }
}

/** 清除指定缓存 */
function clearCache(key: string): void {
  localStorage.removeItem(key);
}

// ==================== 业务级缓存函数 ====================

// -- 项目列表 --

export function getCachedProjectList<T>(): T | null {
  return getCache<T>(KEY_PROJECT_LIST);
}

export function setCachedProjectList<T>(projects: T): void {
  setCache(KEY_PROJECT_LIST, projects, PROJECT_LIST_TTL);
}

// -- 项目内容 --

export function getCachedItemContent(projectId: string): string | null {
  return getCache<string>(`${KEY_ITEM_CONTENT_PREFIX}${projectId}`);
}

export function setCachedItemContent(projectId: string, content: string): void {
  setCache(`${KEY_ITEM_CONTENT_PREFIX}${projectId}`, content, ITEM_CONTENT_TTL);
}

// -- 正则内容 --

export function getCachedRegexContent(projectId: string): string | null | undefined {
  // 返回 undefined 表示缓存未命中, null 表示缓存命中但值为 null (无正则文件)
  const key = `${KEY_REGEX_CONTENT_PREFIX}${projectId}`;
  const raw = localStorage.getItem(key);
  if (!raw) return undefined; // 缓存未命中

  try {
    const entry: CacheEntry<string | null> = JSON.parse(raw);
    const now = Date.now();
    if (now - entry.timestamp > entry.ttl) {
      localStorage.removeItem(key);
      console.info(`[Cache] 缓存过期: ${key}`);
      return undefined;
    }
    console.info(`[Cache] 命中: ${key}`);
    return entry.data; // 可能为 null，表示已确认无正则文件
  } catch (e) {
    localStorage.removeItem(key);
    return undefined;
  }
}

export function setCachedRegexContent(projectId: string, content: string | null): void {
  setCache(`${KEY_REGEX_CONTENT_PREFIX}${projectId}`, content, REGEX_CONTENT_TTL);
}

// -- 缓存失效 --

/** 清除指定项目的内容和正则缓存 */
export function invalidateProjectCache(projectId?: string): void {
  // 始终清除项目列表缓存
  clearCache(KEY_PROJECT_LIST);
  console.info('[Cache] 已清除项目列表缓存');

  if (projectId) {
    clearCache(`${KEY_ITEM_CONTENT_PREFIX}${projectId}`);
    clearCache(`${KEY_REGEX_CONTENT_PREFIX}${projectId}`);
    console.info(`[Cache] 已清除项目 ${projectId} 的缓存`);
  }
}

/** 清除所有创意工坊缓存 */
export function invalidateAllCache(): void {
  const keysToRemove: string[] = [];
  for (let i = 0; i < localStorage.length; i++) {
    const key = localStorage.key(i);
    if (key && key.startsWith(CACHE_PREFIX)) {
      keysToRemove.push(key);
    }
  }
  keysToRemove.forEach(key => localStorage.removeItem(key));
  console.info(`[Cache] 已清除所有缓存 (${keysToRemove.length} 条)`);
}
