// ==================== 统一界面 ====================
// 避免循环依赖，使用动态导入
import { closeModal, escapeHtml, getConfig, saveConfig, showModal } from './utils';
import { deployWorldbookEntry, getCurrentWorldbook, getWorldbookEntries } from './worldbook';
import {
  getCachedProjectList,
  setCachedProjectList,
  getCachedItemContent,
  setCachedItemContent,
  getCachedRegexContent,
  setCachedRegexContent,
  invalidateProjectCache,
  invalidateAllCache,
} from './cache';

// 格式化日期为 YYYY-MM-DD
const formatDate = (dateStr: string | undefined): string => {
  if (!dateStr) return '';
  // 处理 ISO 格式日期 (如 2026-03-18T02:35:41.364Z)
  if (dateStr.includes('T')) {
    return dateStr.split('T')[0];
  }
  // 处理其他格式日期
  return dateStr.substring(0, 10);
};

// 统一数据结构
interface TavernItem {
  id: string; // 对应项目ID
  name: string; // 条目名称
  type: ItemType; // 项目类型：'system' | 'character' | 'event' | 'extension'
  tags: string[]; // 用于筛选和搜索的标签
  metadata: Record<string, any>; // 其他元数据（author、version、description等）
  content: string; // 要部署到世界书的内容
  installed: boolean; // 是否已安装到当前世界书
}

type ItemType = 'system' | 'character' | 'event' | 'extension';

// 后端 API 项目结构
interface ApiProject {
  id: string;
  name: string;
  authorName: string;
  version: string;
  description: string;
  tags: string[];
  updatedAt: string;
  downloadUrl?: string;
}

// 从后端 API 获取项目列表
import { getApiBaseUrl } from './config';

// 记录滑块位置的变量
let scrollPosition = 0;

// 从后端 API 获取已审核项目列表
const fetchProjects = async (forceRefresh = false): Promise<ApiProject[]> => {
  // 优先读取缓存
  if (!forceRefresh) {
    const cached = getCachedProjectList<ApiProject[]>();
    if (cached) {
      console.info(`[CreativeWorkshop] 使用缓存的项目列表 (${cached.length} 个)`);
      return cached;
    }
  }

  try {
    const baseUrl = getApiBaseUrl();
    // 需要显式传递 page 参数，API 默认值似乎不生效
    const url = `${baseUrl}/api/projects?page=0&pageSize=50`;
    console.info(`[CreativeWorkshop] 请求项目列表: ${url}`);

    const res = await fetch(url);
    console.info(`[CreativeWorkshop] 响应状态: ${res.status} ${res.statusText}`);

    // 获取响应内容用于调试
    const responseText = await res.text();
    console.info(`[CreativeWorkshop] 响应内容: ${responseText.substring(0, 500)}`);

    if (!res.ok) {
      let errorData;
      try {
        errorData = JSON.parse(responseText);
      } catch {
        errorData = { error: responseText };
      }
      console.error(`[CreativeWorkshop] HTTP 错误: ${res.status} -`, errorData);
      toastr.error(`获取项目列表失败: ${errorData.error || res.statusText}`);
      return [];
    }

    const data = JSON.parse(responseText);
    console.info(`[CreativeWorkshop] 响应数据:`, data);

    if (!data.success) {
      console.error(`[CreativeWorkshop] API 返回失败:`, data);
      toastr.error('获取项目列表失败: ' + (data.error || '未知错误'));
      return [];
    }

    const projects = data.projects || [];
    // 写入缓存
    setCachedProjectList(projects);
    return projects;
  } catch (error) {
    console.error('[CreativeWorkshop] 获取项目列表异常:', error);
    toastr.error('加载项目列表失败: ' + (error as Error).message);
    return [];
  }
};

// 获取项目内容 - 通过后端 API 代理下载，解决 CORS 问题
const fetchItemContent = async (projectId: string): Promise<string> => {
  // 优先读取缓存
  const cached = getCachedItemContent(projectId);
  if (cached) {
    console.info(`[CreativeWorkshop] 使用缓存的项目内容: ${projectId}`);
    return cached;
  }

  try {
    const baseUrl = getApiBaseUrl();
    // 使用 worker 代理下载文件
    const url = `${baseUrl}/api/files/${projectId}/project-${projectId}.json`;
    console.info(`[CreativeWorkshop] 请求项目内容: ${url}`);

    const res = await fetch(url);
    if (!res.ok) {
      const errorText = await res.text();
      console.error(`[CreativeWorkshop] 获取项目内容失败: ${res.status} - ${errorText}`);
      throw new Error(`无法获取项目内容: ${res.status}`);
    }
    const content = await res.text();
    // 写入缓存
    setCachedItemContent(projectId, content);
    return content;
  } catch (error) {
    console.error(`获取项目 ${projectId} 内容失败:`, error);
    throw new Error(`获取项目 ${projectId} 内容失败: ${(error as Error).message}`);
  }
};

// 获取项目正则内容
const fetchRegexContent = async (projectId: string): Promise<string | null> => {
  // 优先读取缓存（undefined=未命中, null=已确认无正则文件, string=正则内容）
  const cached = getCachedRegexContent(projectId);
  if (cached !== undefined) {
    console.info(`[CreativeWorkshop] 使用缓存的正则内容: ${projectId} (${cached === null ? '无正则' : '有正则'})`);
    return cached;
  }

  try {
    const baseUrl = getApiBaseUrl();
    const url = `${baseUrl}/api/files/${projectId}/regex-${projectId}.json`;
    console.info(`[CreativeWorkshop] 请求正则内容: ${url}`);

    const res = await fetch(url);
    if (!res.ok) {
      // 404 表示没有正则文件，这是正常情况
      if (res.status === 404) {
        // 缓存 null 值，避免重复请求 404
        setCachedRegexContent(projectId, null);
        return null;
      }
      console.error(`[CreativeWorkshop] 获取正则内容失败: ${res.status}`);
      return null;
    }
    const content = await res.text();
    // 写入缓存
    setCachedRegexContent(projectId, content);
    return content;
  } catch (error) {
    console.error(`获取项目 ${projectId} 正则内容失败:`, error);
    return null;
  }
};

// 将 API 项目转换为统一数据结构
const convertToTavernItem = async (project: ApiProject, installedItems: any[]): Promise<TavernItem> => {
  // 从 tags 数组中推断类型
  let type: ItemType = 'system'; // 默认类型

  if (project.tags.includes('角色')) type = 'character';
  else if (project.tags.includes('事件')) type = 'event';
  else if (project.tags.includes('扩展')) type = 'extension';

  // 检查是否已安装 - 通过 extra.fate_project_name 字段精确匹配项目 ID
  const isInstalled = installedItems.some(installedItem => {
    const projectName = installedItem.extra?.fate_project_name || '';
    return projectName === project.id;
  });

  return {
    id: project.id,
    name: project.name,
    type,
    tags: project.tags,
    metadata: {
      author: project.authorName || '未知',
      version: project.version || '1.0.0',
      description: project.description || '暂无简介',
      updateTime: project.updatedAt, // 用于排序
    },
    content: '',
    installed: isInstalled,
  };
};

// 获取所有可部署项目（仅获取基本信息，不获取详细内容）
const getAllTavernItems = async (): Promise<TavernItem[]> => {
  const projects = await fetchProjects();
  const worldbookEntries = await getAllWorldbookEntries();
  return await Promise.all(projects.map(async project => await convertToTavernItem(project, worldbookEntries)));
};

// 获取项目详细内容（仅在需要时调用）
const fetchItemDetail = async (item: TavernItem): Promise<TavernItem> => {
  if (!item.content) {
    item.content = await fetchItemContent(item.id);
  }
  return item;
};

// 从世界书获取所有条目
const getAllWorldbookEntries = async (): Promise<any[]> => {
  const worldbook = getCurrentWorldbook('current');
  return (await getWorldbookEntries(worldbook.primary)) || [];
};

// 根据条目类型获取对应的中文标签
const getTypeLabel = (type: ItemType): string => {
  const labels: Record<ItemType, string> = {
    system: '系统',
    character: '角色',
    event: '事件',
    extension: '扩展',
  };
  return labels[type];
};

// 根据规则重命名条目名称
const renameEntry = (entryName: string, item: TavernItem): string => {
  if (item.type === 'system') {
    // "系统"：检测条目前面是否有"命定系统-"的前缀，没有则添加上
    if (!entryName.startsWith('命定系统-')) {
      return `命定系统-${entryName}`;
    }
    return entryName;
  } else {
    // "角色，事件，扩展"：检测条目前面是否有"[DLC]"的前缀，没有则添加前缀"[DLC][$1][$2]"
    // $1为"角色，事件，扩展"三选一，即对应的tag；$2为{item.name}
    if (!entryName.startsWith('[DLC]')) {
      const typeLabel = getTypeLabel(item.type);
      return `[DLC][${typeLabel}][${item.name}]${entryName}`;
    }
    return entryName;
  }
};

// 部署项目
const deployItem = async (item: TavernItem) => {
  try {
    toastr.info(`正在部署 ${item.name}...`, '', { timeOut: 0 });
    const worldbook = getCurrentWorldbook('current');

    // 通过 API 获取项目内容
    const content = await fetchItemContent(item.id);
    const data = JSON.parse(content);

    // 遍历所有条目并部署
    const entries = Object.values(data.entries || {}) as any[];
    for (const entry of entries) {
      // 根据规则重命名条目
      const originalName = entry.comment || '无标题';
      const renamedName = renameEntry(originalName, item);

      // 构建条目配置（与 worldbook.ts 中 deployWorldbookEntry 期望的格式一致）
      const entryConfig = {
        name: renamedName,
        enabled: !entry.disable,
        constant: entry.constant,
        selective: entry.selective,
        selectiveLogic: entry.selectiveLogic,
        key: entry.key,
        keysecondary: entry.keysecondary,
        scanDepth: entry.scanDepth,
        depth: entry.depth,
        displayIndex: entry.displayIndex,
        role: entry.role,
        order: entry.order,
        excludeRecursion: entry.excludeRecursion,
        preventRecursion: entry.preventRecursion,
        delayUntilRecursion: entry.delayUntilRecursion,
        sticky: entry.sticky,
        cooldown: entry.cooldown,
        delay: entry.delay,
        useProbability: entry.useProbability,
        probability: entry.probability,
        comment: entry.comment || item.metadata.description,
      };

      // 传入项目 ID 作为 fate_project_name
      await deployWorldbookEntry(worldbook.primary, renamedName, entryConfig, entry.content, item.id);
    }

    toastr.clear();
    toastr.success(`成功部署 ${item.name} (共${entries.length}个条目)`, '项目部署完成');

    // 部署正则（如果有）
    try {
      const regexContent = await fetchRegexContent(item.id);
      if (regexContent) {
        let regexData = JSON.parse(regexContent);
        // 兼容单个正则对象（非数组）的情况
        if (!Array.isArray(regexData)) {
          regexData = [regexData];
        }
        if (regexData.length > 0) {
          // 将 JSON 格式的正则转换为 TavernRegex 格式
          const newRegexes = regexData.map((r: any) => {
            const placements: number[] = r.placement || [];
            return {
              id: r.id || crypto.randomUUID(),
              script_name: r.scriptName || '',
              enabled: !r.disabled,
              run_on_edit: !!r.runOnEdit,
              scope: 'character' as const,
              find_regex: r.findRegex || '',
              trim_strings: Array.isArray(r.trimStrings) ? r.trimStrings.join(',') : r.trimStrings || '',
              replace_string: r.replaceString || '',
              source: {
                user_input: placements.includes(1),
                ai_output: placements.includes(2),
                slash_command: placements.includes(3),
                world_info: placements.includes(4),
              },
              destination: {
                display: r.markdownOnly ? true : !r.promptOnly,
                prompt: r.promptOnly ? true : !r.markdownOnly,
              },
              min_depth: r.minDepth ?? null,
              max_depth: r.maxDepth ?? null,
            };
          });

          await updateTavernRegexesWith(
            regexes => {
              return [...regexes, ...newRegexes];
            },
            { scope: 'character' },
          );

          toastr.success(`成功导入 ${newRegexes.length} 条正则`, '正则导入完成');
        }
      }
    } catch (regexError: any) {
      console.warn(`正则导入失败: ${regexError.message}`);
      // 正则导入失败不影响整体部署
    }

    // 更新项目安装状态
    item.installed = true;
    // 清除项目列表缓存（安装状态变化）
    invalidateProjectCache();
  } catch (e: any) {
    toastr.clear();
    toastr.error(`部署失败: ${e.message}`);
  }
};

// 卸载项目
const uninstallItem = async (item: TavernItem) => {
  try {
    toastr.info(`正在卸载 ${item.name}...`, '', { timeOut: 0 });
    const worldbook = getCurrentWorldbook('current');

    // 通过 extra.fate_project_name 字段匹配要卸载的条目（使用项目 ID 匹配）
    const result = await deleteWorldbookEntries(
      worldbook.primary,
      (existingEntry: any) => existingEntry.extra?.fate_project_name === item.id,
    );

    const deletedCount = result.deleted_entries?.length || 0;
    if (deletedCount > 0) {
      toastr.clear();
      toastr.success(`成功卸载 ${item.name} (共${deletedCount}个条目)`, '项目卸载完成');
    } else {
      // 如果没有找到通过 extra 字段匹配的条目，尝试通过项目名称作为 comment 的一部分匹配（旧方式兼容）
      const fallbackResult = await deleteWorldbookEntries(worldbook.primary, (existingEntry: any) => {
        // 尝试匹配 comment 字段中包含项目名称的条目（用于兼容旧数据）
        const comment = existingEntry.comment || '';
        return comment.includes(item.name) || existingEntry.name === item.name;
      });
      const fallbackCount = fallbackResult.deleted_entries?.length || 0;
      toastr.clear();
      if (fallbackCount > 0) {
        toastr.success(`成功卸载 ${item.name} (共${fallbackCount}个条目)`, '项目卸载完成');
      } else {
        toastr.warning(`未找到已安装的 ${item.name} 条目`, '卸载完成');
      }
    }

    // 卸载正则（如果有）
    try {
      const regexContent = await fetchRegexContent(item.id);
      if (regexContent) {
        let regexData = JSON.parse(regexContent);
        // 兼容单个正则对象（非数组）的情况
        if (!Array.isArray(regexData)) {
          regexData = [regexData];
        }
        if (regexData.length > 0) {
          // 获取正则文件中所有的 scriptName
          const scriptNames = regexData.map((r: any) => r.scriptName).filter(Boolean);
          if (scriptNames.length > 0) {
            await updateTavernRegexesWith(regexes => {
              return regexes.filter(regex => !scriptNames.includes(regex.script_name));
            });
            toastr.success(`成功卸载 ${scriptNames.length} 条正则`, '正则卸载完成');
          }
        }
      }
    } catch (regexError: any) {
      console.warn(`正则卸载失败: ${regexError.message}`);
      // 正则卸载失败不影响整体卸载
    }

    // 更新项目安装状态
    item.installed = false;
    // 清除项目列表缓存（安装状态变化）
    invalidateProjectCache();
  } catch (e: any) {
    toastr.clear();
    toastr.error(`卸载失败: ${e.message}`);
  }
};

