// 打开统一界面
export const openUnifiedPanel = async () => {
  console.info('[CreativeWorkshop] 正在打开统一面板...');

  const config = getConfig();

  // 显示加载状态
  toastr.info('正在加载项目列表...', '', { timeOut: 0 });

  const allItems = await getAllTavernItems();

  console.info(`[CreativeWorkshop] 获取到 ${allItems.length} 个项目`);

  if (allItems.length === 0) {
    toastr.warning('未获取到任何项目，请检查网络连接或 API 配置');
  } else {
    toastr.clear();
  }
  const currentFilters = config.filters || { system: true, character: true, event: true, extension: true };
  let currentInstalledFilter = config.installedFilter || 'all'; // 'all', 'installed', 'uninstalled'
  let currentSortBy = config.sortBy || 'updateTime'; // 'updateTime', 'name', 'author'
  const selectedItem: TavernItem | null = null;

  // 筛选项目
  const filterItems = () => {
    let filtered = allItems.filter(item => {
      const typeMatch = currentFilters[item.type];
      const installedMatch =
        currentInstalledFilter === 'all'
          ? true
          : currentInstalledFilter === 'installed'
            ? item.installed
            : !item.installed;
      return typeMatch && installedMatch;
    });

    // 应用排序
    filtered = [...filtered].sort((a, b) => {
      switch (currentSortBy) {
        case 'name':
          return a.name.localeCompare(b.name, 'zh-CN');
        case 'author':
          return (a.metadata.author || '').localeCompare(b.metadata.author || '', 'zh-CN');
        case 'updateTime':
        default:
          // 假设 updateTime 格式为 YYYY-MM-DD 或类似的可比较字符串
          return (b.metadata.updateTime || '').localeCompare(a.metadata.updateTime || '', 'zh-CN');
      }
    });

    return filtered;
  };

  // 渲染界面
  const renderPanel = () => {
    // 记录当前滑块位置
    const currentTargetDoc = window.top?.document || document;
    const gridElement = currentTargetDoc.querySelector('.fate-grid');
    if (gridElement) {
      scrollPosition = gridElement.scrollTop;
      console.info(`记录滑块位置: ${scrollPosition}px`);
    }

    const filteredItems = filterItems();

    // 渲染类型筛选器
    const typeFiltersHtml = `
      <div class="fate-type-filters" style="display:flex; gap:12px; margin-bottom:12px; flex-wrap:wrap;">
        <label style="display:flex; align-items:center; gap:8px; cursor:pointer;">
          <input type="checkbox" ${currentFilters.system ? 'checked' : ''} data-type="system">
          <span style="color: var(--color-system-light); font-weight:600;"><i class="fas fa-cog" style="margin-right:4px;"></i>系统</span>
        </label>
        <label style="display:flex; align-items:center; gap:8px; cursor:pointer;">
          <input type="checkbox" ${currentFilters.character ? 'checked' : ''} data-type="character">
          <span style="color: var(--color-character-light); font-weight:600;"><i class="fas fa-user" style="margin-right:4px;"></i>角色</span>
        </label>
        <label style="display:flex; align-items:center; gap:8px; cursor:pointer;">
          <input type="checkbox" ${currentFilters.event ? 'checked' : ''} data-type="event">
          <span style="color: var(--color-event-light); font-weight:600;"><i class="fas fa-calendar-alt" style="margin-right:4px;"></i>事件</span>
        </label>
        <label style="display:flex; align-items:center; gap:8px; cursor:pointer;">
          <input type="checkbox" ${currentFilters.extension ? 'checked' : ''} data-type="extension">
          <span style="color: var(--color-extension-light); font-weight:600;"><i class="fas fa-puzzle-piece" style="margin-right:4px;"></i>扩展</span>
        </label>
      </div>
    `;

    // 渲染已安装状态筛选器和排序选择
    const installedFiltersHtml = `
      <div class="fate-installed-filters">
        <label style="display:flex; align-items:center; justify-content:center; gap:6px; cursor:pointer; flex:1; padding:8px 12px;">
          <input type="radio" name="installed" ${currentInstalledFilter === 'all' ? 'checked' : ''} value="all">
          <span>显示所有</span>
        </label>
        <label style="display:flex; align-items:center; justify-content:center; gap:6px; cursor:pointer; flex:1; padding:8px 12px;">
          <input type="radio" name="installed" ${currentInstalledFilter === 'installed' ? 'checked' : ''} value="installed">
          <span>已安装</span>
        </label>
        <label style="display:flex; align-items:center; justify-content:center; gap:6px; cursor:pointer; flex:1; padding:8px 12px;">
          <input type="radio" name="installed" ${currentInstalledFilter === 'uninstalled' ? 'checked' : ''} value="uninstalled">
          <span>未安装</span>
        </label>
        <label style="display:flex; align-items:center; justify-content:center; gap:6px; cursor:pointer; flex:1; padding:8px 12px; border:none; background:transparent;">
          <span style="opacity:0.7; white-space:nowrap;">排序:</span>
          <select id="sort-select" style="flex:1; min-width:0;">
            <option value="updateTime" ${currentSortBy === 'updateTime' ? 'selected' : ''}>更新日期</option>
            <option value="name" ${currentSortBy === 'name' ? 'selected' : ''}>项目名称</option>
            <option value="author" ${currentSortBy === 'author' ? 'selected' : ''}>作者</option>
          </select>
        </label>
      </div>
    `;

    // 渲染项目网格
    const gridHtml = `
      <div class="fate-grid">
        ${filteredItems.map(item => renderItemCard(item, config)).join('')}
      </div>
    `;

    // 渲染详情面板（如果有选中项）
    const detailHtml = selectedItem
      ? `
      <div class="fate-preview-wrapper" style="display: flex;">
        ${renderItemDetail(selectedItem)}
      </div>
    `
      : '';

    const html = `
      <div class="fate-header">
        <h3><i class="fas fa-tools" style="margin-right:10px;"></i>命定创意工坊</h3>
        <div style="display:flex; gap:8px;">
          <button class="fate-icon-btn" id="refresh-btn" title="刷新数据" style="background: rgba(255,255,255,0.06);"><i class="fas fa-sync-alt"></i></button>
          <button class="fate-icon-btn" id="upload-btn" title="上传项目" style="background: linear-gradient(135deg, var(--color-primary), #4F46E5);"><i class="fas fa-cloud-upload-alt"></i></button>
          <button class="fate-icon-btn" id="settings-btn" title="界面设置"><i class="fas fa-cog"></i></button>
        </div>
      </div>
      <div class="fate-filters">
        ${typeFiltersHtml}
        ${installedFiltersHtml}
      </div>
      <div class="fate-search">
        <input type="text" id="search-input" placeholder="🔍 搜索项目、作者、标签...">
      </div>
      <div class="fate-main-container">
        ${gridHtml}
        ${detailHtml}
      </div>
    `;

    // 检查是否已经有模态框，如果有，只更新内容，否则创建新的模态框
    const targetDoc = window.top?.document || document;
    const existingModal = targetDoc.querySelector('.fate-modal-overlay');

    if (existingModal) {
      const modalContent = existingModal.querySelector('.fate-modal-content');
      if (modalContent) {
        modalContent.innerHTML = html;
        // 重新绑定事件
        bindEvents(targetDoc, modalContent as HTMLElement);
        // 恢复滑块位置
        const newGridElement = modalContent.querySelector('.fate-grid');
        if (newGridElement && scrollPosition > 0) {
          newGridElement.scrollTop = scrollPosition;
          console.info(`恢复滑块位置: ${scrollPosition}px`);
        }
      }
    } else {
      showModal(html, (doc, modalContent) => {
        bindEvents(doc, modalContent);
        // 恢复滑块位置（如果是第一次创建模态框，可能不需要恢复）
        if (scrollPosition > 0) {
          const newGridElement = modalContent.querySelector('.fate-grid');
          if (newGridElement) {
            newGridElement.scrollTop = scrollPosition;
            console.info(`恢复滑块位置: ${scrollPosition}px`);
          }
        }
      });
    }
  };

  // 将函数挂载到window对象上以避免循环依赖
  (window as any).openUnifiedPanel = openUnifiedPanel;

  // 绑定事件的函数
  const bindEvents = (doc: Document, modalContent: HTMLElement) => {
    // 绑定刷新按钮事件
    const refreshBtn = doc.getElementById('refresh-btn');
    if (refreshBtn) {
      refreshBtn.onclick = async e => {
        e.stopPropagation();
        invalidateAllCache();
        toastr.info('正在刷新数据...', '', { timeOut: 0 });
        // 关闭当前面板并重新打开
        const targetDoc = window.top?.document || document;
        const existingModal = targetDoc.querySelector('.fate-modal-overlay');
        if (existingModal) existingModal.remove();
        await openUnifiedPanel();
      };
    }

    // 绑定上传按钮事件
    const uploadBtn = doc.getElementById('upload-btn');
    if (uploadBtn) {
      uploadBtn.onclick = e => {
        e.stopPropagation();
        import('./uploadPanel').then(module => module.openUploadPanel());
      };
    }

    // 绑定设置按钮事件
    const settingsBtn = doc.getElementById('settings-btn');
    if (settingsBtn) {
      settingsBtn.onclick = e => {
        e.stopPropagation();
        import('./settings').then(module => module.openSystemUpdaterSettings());
      };
    }

    // 绑定类型筛选器事件
    doc.querySelectorAll('.fate-type-filters input[type="checkbox"]').forEach(checkbox => {
      checkbox.addEventListener('change', (e: any) => {
        const type = e.target.getAttribute('data-type');
        currentFilters[type as keyof typeof currentFilters] = e.target.checked;
        config.filters = currentFilters;
        saveConfig(config);
        renderPanel();
      });
    });

    // 绑定已安装状态筛选器事件
    doc.querySelectorAll('.fate-installed-filters input[type="radio"]').forEach(radio => {
      radio.addEventListener('change', (e: any) => {
        currentInstalledFilter = e.target.value;
        config.installedFilter = currentInstalledFilter;
        saveConfig(config);
        renderPanel();
      });
    });

    // 绑定排序选择事件
    const sortSelect = doc.getElementById('sort-select') as HTMLSelectElement | null;
    if (sortSelect) {
      sortSelect.addEventListener('change', (e: any) => {
        currentSortBy = e.target.value;
        config.sortBy = currentSortBy;
        saveConfig(config);
        renderPanel();
      });
    }

    // 绑定搜索事件（使用防抖以避免频繁刷新）
    const searchInput = doc.getElementById('search-input') as HTMLInputElement | null;
    if (searchInput) {
      let searchTimeout: number;
      searchInput.addEventListener('input', () => {
        clearTimeout(searchTimeout);
        searchTimeout = window.setTimeout(() => {
          const searchTerm = searchInput.value.toLowerCase().trim();
          const cards = modalContent.querySelectorAll('.fate-card');

          cards.forEach(card => {
            const searchData = card.getAttribute('data-search') || '';
            const cardElement = card as HTMLElement;
            if (searchTerm === '' || searchData.includes(searchTerm)) {
              cardElement.style.display = 'flex';
            } else {
              cardElement.style.display = 'none';
            }
          });
        }, 300); // 300ms防抖
      });
    }

    // 绑定详情按钮事件
    doc.querySelectorAll('.fate-card .detail-btn').forEach(btn => {
      btn.addEventListener('click', async (e: any) => {
        e.stopPropagation();
        const btnElement = e.target.closest('.detail-btn');
        const id = btnElement.getAttribute('data-id');
        const item = allItems.find(item => item.id === id)!;

        // 获取对应选项的世界书条目内容
        let worldbookEntries: any[] = [];
        try {
          const content = await fetchItemContent(item.id);
          if (content && content !== '获取内容失败') {
            const data = JSON.parse(content);
            worldbookEntries = Object.values(data.entries || {});
          }
        } catch (error) {
          console.error(`Error loading worldbook entries for ${item.id}:`, error);
          worldbookEntries = [];
        }

        // 渲染详情弹窗
        const detailModalHtml = `
            <div class="fate-header">
              <h3><i class="fas fa-info-circle" style="margin-right:10px;"></i>${escapeHtml(item.name)} <span style="opacity:0.5; font-weight:400;">·</span> <span style="font-weight:400; opacity:0.7;">详情</span></h3>
            </div>
            <div class="fate-detail-container" style="flex: 1; overflow-y: auto; padding: var(--space-5);">
              <div class="fate-detail-item">
                <span class="fate-detail-label"><i class="fas fa-tag" style="margin-right:6px;"></i>名称</span>
                <span class="fate-detail-value">${escapeHtml(item.name)}</span>
              </div>
              <div class="fate-detail-item">
                <span class="fate-detail-label"><i class="fas fa-user-edit" style="margin-right:6px;"></i>作者</span>
                <span class="fate-detail-value">${escapeHtml(item.metadata.author)}</span>
              </div>
              <div class="fate-detail-item">
                <span class="fate-detail-label"><i class="fas fa-tag" style="margin-right:6px;"></i>版本</span>
                <span class="fate-detail-value">${escapeHtml(item.metadata.version || '1.0.0')}</span>
              </div>
              <div class="fate-detail-item">
                <span class="fate-detail-label"><i class="fas fa-clock" style="margin-right:6px;"></i>更新日期</span>
                <span class="fate-detail-value">${formatDate(item.metadata.updateTime)}</span>
              </div>
              <div class="fate-detail-item">
                <span class="fate-detail-label"><i class="fas fa-tags" style="margin-right:6px;"></i>标签</span>
                <span class="fate-detail-value">${item.tags.map(t => escapeHtml(t)).join(', ')}</span>
              </div>
              <div class="fate-detail-item" style="border-bottom:none; flex-direction:column; align-items:flex-start;">
                <div class="fate-detail-label" style="margin-bottom:8px;"><i class="fas fa-align-left" style="margin-right:6px;"></i>简介</div>
                <div style="opacity:0.9; line-height:1.6; background:rgba(0,0,0,0.2); padding:12px; border-radius:8px; width:100%;">${escapeHtml(item.metadata.description)}</div>
              </div>
              <div style="margin-top:20px; width:100%;">
                <div class="fate-detail-label" style="margin-bottom:10px;"><i class="fas fa-book" style="margin-right:6px;"></i>世界书条目（${worldbookEntries.length}个）</div>
                ${worldbookEntries
                  .map(
                    (entry, index) => `
                  <div class="fate-accordion" style="margin-bottom:10px;">
                    <div class="fate-accord-header" data-index="${index}" style="cursor:pointer;">
                      <span><i class="fas fa-file-alt" style="margin-right:8px; opacity:0.7;"></i>${escapeHtml(entry.comment || '无标题')}</span>
                      <i class="fas fa-chevron-down" style="transition: transform 0.2s; opacity:0.6;"></i>
                    </div>
                    <div class="fate-accord-body" data-index="${index}" style="display:none; padding:14px;">
                      <div class="fate-detail-item">
                        <span class="fate-detail-label"><i class="fas fa-key" style="margin-right:6px;"></i>关键词</span>
                        <span class="fate-detail-value">${entry.key ? (Array.isArray(entry.key) ? entry.key.map((k: string) => escapeHtml(k)).join(', ') : escapeHtml(entry.key)) : '无'}</span>
                      </div>
                      <div class="fate-detail-item">
                        <span class="fate-detail-label"><i class="fas fa-keys" style="margin-right:6px;"></i>次要关键词</span>
                        <span class="fate-detail-value">${entry.keysecondary ? (Array.isArray(entry.keysecondary) ? entry.keysecondary.map((k: string) => escapeHtml(k)).join(', ') : escapeHtml(entry.keysecondary)) : '无'}</span>
                      </div>
                      <div class="fate-detail-item" style="border-bottom:none; flex-direction:column; align-items:flex-start;">
                        <div class="fate-detail-label" style="margin-bottom:6px;"><i class="fas fa-align-left" style="margin-right:6px;"></i>内容</div>
                        <div style="opacity:0.9; line-height:1.6; background:rgba(0,0,0,0.2); padding:10px; border-radius:6px; width:100%; font-family: monospace; white-space: pre-wrap; font-size:0.85em;">${escapeHtml(entry.content || '无')}</div>
                      </div>
                    </div>
                  </div>
                `,
                  )
                  .join('')}
              </div>
            </div>
            <div class="fate-footer">
              <button class="fate-apply-btn" id="close-detail-btn" style="background: linear-gradient(135deg, #6366F1, #4F46E5);">关闭</button>
            </div>
          `;

        showModal(
          detailModalHtml,
          modalDoc => {
            const closeBtn = modalDoc.getElementById('close-detail-btn');
            if (closeBtn) {
              (closeBtn as HTMLButtonElement).onclick = (e: MouseEvent) => {
                e.stopPropagation();
                closeModal();
              };
            }

            // 绑定折叠块点击事件
            modalDoc.querySelectorAll('.fate-accord-header').forEach(header => {
              (header as HTMLElement).onclick = (e: MouseEvent) => {
                e.stopPropagation();
                const index = (header as HTMLElement).getAttribute('data-index');
                const body = modalDoc.querySelector(`.fate-accord-body[data-index="${index}"]`);
                const icon = header.querySelector('i');

                if (body) {
                  const bodyElement = body as HTMLElement;
                  if (bodyElement.style.display === 'none') {
                    bodyElement.style.display = 'block';
                    if (icon) {
                      (icon as HTMLElement).style.transform = 'rotate(180deg)';
                    }
                  } else {
                    bodyElement.style.display = 'none';
                    if (icon) {
                      (icon as HTMLElement).style.transform = 'rotate(0deg)';
                    }
                  }
                }
              };
            });
          },
          true,
        );
      });
    });

    // 绑定部署按钮事件
    doc.querySelectorAll('.fate-card .deploy-btn').forEach(btn => {
      btn.addEventListener('click', async (e: any) => {
        e.stopPropagation();
        const id = e.target.closest('.deploy-btn').getAttribute('data-id');
        const item = allItems.find(item => item.id === id)!;
        await deployItem(item);
        renderPanel();
      });
    });

    // 绑定卸载按钮事件
    doc.querySelectorAll('.fate-card .uninstall-btn').forEach(btn => {
      btn.addEventListener('click', async (e: any) => {
        e.stopPropagation();
        const id = e.target.closest('.uninstall-btn').getAttribute('data-id');
        const item = allItems.find(item => item.id === id)!;
        await uninstallItem(item);
        renderPanel();
      });
    });
  };

  renderPanel();
};
