// ==================== 设置面板 ====================
import { adjustColor, getConfig, injectGlobalStyles, isLightColor, saveConfig } from './utils';

export const openSystemUpdaterSettings = (): void => {
  let targetDoc = document;
  try {
    if (window.top?.document) targetDoc = window.top.document;
  } catch (e) {
    // cross-origin
  }

  // 注入全局样式
  injectGlobalStyles(targetDoc);
  const config = getConfig();

  // 查找或创建模态框
  let modalOverlay = targetDoc.querySelector('.fate-modal-overlay') as HTMLElement | null;
  if (!modalOverlay) {
    // 创建新的模态框
    modalOverlay = targetDoc.createElement('div') as HTMLElement;
    modalOverlay.className = 'fate-modal-overlay';
    Object.assign(modalOverlay.style, {
      position: 'fixed',
      top: '0',
      left: '0',
      width: '100%',
      height: '100%',
      zIndex: '2147483647',
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'flex-start',
      paddingTop: '20px',
      paddingBottom: '20px',
      backgroundColor: 'rgba(0,0,0,0.7)',
      backdropFilter: 'blur(4px)',
      boxSizing: 'border-box',
    });

    const modalContent = targetDoc.createElement('div');
    modalContent.className = 'fate-modal-content';
    Object.assign(modalContent.style, {
      backgroundColor: config.bgColor,
      color: config.textColor,
      borderRadius: '16px',
      padding: '20px',
      minWidth: '320px',
      maxWidth: '90%',
      maxHeight: 'calc(90vh - 40px)',
      overflow: 'auto',
    });

    // 设置 CSS 变量
    const cardDark = adjustColor(config.cardColor, -20);
    const cardLight = adjustColor(config.cardColor, 20);
    modalContent.style.setProperty('--bg-color', config.bgColor);
    modalContent.style.setProperty('--card-base', config.cardColor);
    modalContent.style.setProperty('--card-dark', cardDark);
    modalContent.style.setProperty('--card-light', cardLight);
    modalContent.style.setProperty('--text-color', config.textColor);
    modalContent.style.setProperty('--highlight-color', isLightColor(config.bgColor) ? '#FF6F00' : '#FFD700');

    modalOverlay.appendChild(modalContent);
    targetDoc.body.appendChild(modalOverlay);

    // 点击模态框外部关闭
    modalOverlay.onclick = (e: MouseEvent) => {
      if (e.target === modalOverlay && modalOverlay) {
        modalOverlay.remove();
      }
    };
  }

  // 检查是否已有设置面板，并移除
  const existing = targetDoc.getElementById('sys-updater-settings-overlay');
  if (existing) existing.remove();

  const settingsOverlay = targetDoc.createElement('div');
  settingsOverlay.id = 'sys-updater-settings-overlay';
  Object.assign(settingsOverlay.style, {
    position: 'absolute',
    top: '0',
    left: '0',
    width: '100%',
    height: '100%',
    backgroundColor: 'rgba(0,0,0,0.6)',
    zIndex: '200',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    backdropFilter: 'blur(2px)',
  });
  settingsOverlay.onclick = e => e.stopPropagation();

  const currentConfig = getConfig();
  const settingsBox = targetDoc.createElement('div');
  Object.assign(settingsBox.style, {
    backgroundColor: '#263238',
    color: '#ECEFF1',
    padding: '20px',
    borderRadius: '16px',
    minWidth: '320px',
    maxWidth: '90%',
  });

  settingsBox.innerHTML = `
    <h3 style="margin:0 0 24px 0; display:flex; align-items:center; gap:12px; font-size:1.5rem; font-weight:700;">
      <i class="fas fa-cog" style="background: linear-gradient(135deg, #6366F1, #8B5CF6); -webkit-background-clip: text; -webkit-text-fill-color: transparent;"></i> 界面设置
    </h3>
    <div style="margin-bottom:28px;">
      <label style="display:block; margin-bottom:14px; opacity:0.8; font-weight:600; font-size:0.95rem;">窗口宽度</label>
      <div style="display:flex; flex-direction:column; gap:10px;">
        <input type="range" id="settings-width" min="600" max="1400" value="${currentConfig.width}"
               style="width:100%; height:8px; border-radius:4px; background:linear-gradient(90deg, rgba(99,102,241,0.3), rgba(139,92,246,0.3)); outline:none; -webkit-appearance:none;">
        <div style="display:flex; justify-content:space-between; font-size:0.875em; opacity:0.6;">
          <span>600px</span>
          <span id="width-display" style="font-weight:600; color:#6366F1;">${currentConfig.width}px</span>
          <span>1400px</span>
        </div>
      </div>
    </div>
    <div style="margin-bottom:28px;">
      <label style="display:block; margin-bottom:14px; opacity:0.8; font-weight:600; font-size:0.95rem;">窗口高度</label>
      <div style="display:flex; flex-direction:column; gap:10px;">
        <input type="range" id="settings-height" min="40" max="95" value="${currentConfig.height}"
               style="width:100%; height:8px; border-radius:4px; background:linear-gradient(90deg, rgba(16,185,129,0.3), rgba(59,130,246,0.3)); outline:none; -webkit-appearance:none;">
        <div style="display:flex; justify-content:space-between; font-size:0.875em; opacity:0.6;">
          <span>40%</span>
          <span id="height-display" style="font-weight:600; color:#10B981;">${currentConfig.height}%</span>
          <span>95%</span>
        </div>
      </div>
    </div>
    <div style="display:flex; gap:14px; justify-content:flex-end; margin-top:28px; padding-top:20px; border-top:1px solid rgba(255,255,255,0.1);">
      <button id="settings-cancel" style="
        flex:1;
        padding:14px 28px;
        border-radius:12px;
        border:1px solid rgba(255,255,255,0.2);
        background:rgba(255,255,255,0.05);
        color:#E2E8F0;
        cursor:pointer;
        font-weight:600;
        transition:all 0.2s;
        font-size:0.9rem;">取消
      </button>
      <button id="settings-save" style="
        flex:1;
        padding:14px 28px;
        border-radius:12px;
        border:none;
        background:linear-gradient(135deg, #6366F1, #4F46E5);
        color:white;
        cursor:pointer;
        font-weight:600;
        transition:all 0.2s;
        font-size:0.9rem;
        box-shadow:0 4px 15px rgba(99, 102, 241, 0.4);">保存
      </button>
    </div>
  `;

  // 找到模态框内容容器
  let modalContent = modalOverlay.querySelector('.fate-modal-content') as HTMLElement;
  if (!modalContent) {
    // 如果没有内容容器，创建一个
    modalContent = targetDoc.createElement('div');
    modalContent.className = 'fate-modal-content';
    Object.assign(modalContent.style, {
      backgroundColor: config.bgColor,
      color: config.textColor,
      borderRadius: '16px',
      padding: '20px',
      minWidth: '320px',
      maxWidth: '90%',
      maxHeight: '90vh',
      overflow: 'auto',
    });
    // 设置 CSS 变量
    const cardDark = adjustColor(config.cardColor, -20);
    const cardLight = adjustColor(config.cardColor, 20);
    modalContent.style.setProperty('--bg-color', config.bgColor);
    modalContent.style.setProperty('--card-base', config.cardColor);
    modalContent.style.setProperty('--card-dark', cardDark);
    modalContent.style.setProperty('--card-light', cardLight);
    modalContent.style.setProperty('--text-color', config.textColor);
    modalContent.style.setProperty('--highlight-color', isLightColor(config.bgColor) ? '#FF6F00' : '#FFD700');
    modalOverlay.appendChild(modalContent);
  }

  settingsOverlay.appendChild(settingsBox);
  modalContent.appendChild(settingsOverlay);

  const widthInput = settingsBox.querySelector('#settings-width') as HTMLInputElement;
  const heightInput = settingsBox.querySelector('#settings-height') as HTMLInputElement;
  const widthDisplay = settingsBox.querySelector('#width-display') as HTMLElement;
  const heightDisplay = settingsBox.querySelector('#height-display') as HTMLElement;

  widthInput.oninput = () => {
    widthDisplay.innerText = widthInput.value + 'px';
  };
  heightInput.oninput = () => {
    heightDisplay.innerText = heightInput.value + '%';
  };

  const cancelBtn = settingsBox.querySelector('#settings-cancel') as HTMLButtonElement;
  const saveBtn = settingsBox.querySelector('#settings-save') as HTMLButtonElement;

  cancelBtn.onclick = () => settingsOverlay.remove();
  saveBtn.onclick = () => {
    currentConfig.width = parseInt(widthInput.value);
    currentConfig.height = parseInt(heightInput.value);
    saveConfig(currentConfig);
    // 关闭设置面板
    settingsOverlay.remove();
    // 立即应用新配色到当前界面
    applyCurrentConfig();
    // 重新加载面板以更新数据
    reloadCurrentPanel();
  };
};

export const reloadCurrentPanel = (): void => {
  const targetDoc = window.top?.document || document;
  const modalContent = targetDoc.querySelector('#custom-system-modal > div.fate-modal-content') as HTMLElement;
  if (!modalContent) return;

  // 只支持统一界面的重载
  if (modalContent.querySelector('.fate-type-filters') || modalContent.querySelector('.fate-installed-filters')) {
    // 简单的重新加载方式：关闭当前模态框
    const customModal = targetDoc.getElementById('custom-system-modal');
    if (customModal) customModal.remove();

    // 使用动态导入避免循环依赖
    requestAnimationFrame(async () => {
      const { openUnifiedPanel } = await import('./unifiedPanel');
      openUnifiedPanel();
    });
  }
};

// 应用当前配置到界面
export const applyCurrentConfig = (): void => {
  const targetDoc = window.top?.document || document;
  const config = getConfig();

  // 注入全局样式
  injectGlobalStyles(targetDoc);

  // 更新现有模态框的样式变量
  const modalContent = targetDoc.querySelector('.fate-modal-content');
  if (modalContent) {
    const cardDark = adjustColor(config.cardColor, -20);
    const cardLight = adjustColor(config.cardColor, 20);
    const highlightColor = isLightColor(config.bgColor) ? '#FF6F00' : '#FFD700';

    (modalContent as HTMLElement).style.setProperty('--bg-color', config.bgColor);
    (modalContent as HTMLElement).style.setProperty('--card-base', config.cardColor);
    (modalContent as HTMLElement).style.setProperty('--card-dark', cardDark);
    (modalContent as HTMLElement).style.setProperty('--card-light', cardLight);
    (modalContent as HTMLElement).style.setProperty('--text-color', config.textColor);
    (modalContent as HTMLElement).style.setProperty('--highlight-color', highlightColor);

    // 更新宽度和高度
    (modalContent as HTMLElement).style.maxWidth = config.width + 'px';
    (modalContent as HTMLElement).style.width = '95%';
    (modalContent as HTMLElement).style.maxHeight = config.height + 'vh';
  }
};
