import { invalidateProjectCache } from './cache';

// 处理 OAuth 回调 URL 参数（当回调页面刷新父窗口时会被调用）
const handleOAuthCallbackFromUrl = (): boolean => {
  const hash = window.location.hash;
  const params = new URLSearchParams(window.location.search);

  // 检查是否是 OAuth 成功回调
  let token = params.get('token');
  let userStr = params.get('user');

  // 如果没有在查询参数中找到token，检查hash中是否有oauth-success格式的token
  if (!token && hash.startsWith('#oauth-success=')) {
    token = hash.substring('#oauth-success='.length);
    // 尝试从sessionStorage获取用户信息（因为hash中只包含token）
    try {
      userStr = sessionStorage.getItem('cw_userData');
    } catch (e) {
      console.error('从sessionStorage获取用户信息失败:', e);
    }
  }

  if (token && userStr) {
    try {
      const user = JSON.parse(decodeURIComponent(userStr));
      console.info('从 URL 参数解析到用户信息:', user);

      // 保存 Token 信息
      localStorage.setItem(TOKEN_KEY, token);
      localStorage.setItem(USER_KEY, JSON.stringify(user));

      // 清除 URL 参数和hash
      window.history.replaceState(null, '', window.location.pathname);

      toastr.success('登录成功！');
      return true;
    } catch (e) {
      console.error('解析 OAuth 回调参数失败:', e);
    }
  }
  return false;
};

// 初始化时检查 URL 参数
if (typeof window !== 'undefined') {
  handleOAuthCallbackFromUrl();
}

// 用户信息
interface User {
  id: string;
  username: string;
  avatar: string;
  avatarUrl: string;
  isAdmin: boolean;
}

// 项目信息
interface Project {
  id: string;
  name: string;
  description: string;
  version: string;
  authorId: string;
  authorName: string;
  authorAvatar: string;
  status: 'pending' | 'approved' | 'rejected';
  downloadUrl: string;
  fileSize: number;
  tags: string[];
  coverImage: string;
  createdAt: string;
  updatedAt: string;
  rejectReason?: string;
}

// 当前登录用户
let currentUser: User | null = null;

// 获取当前用户
export const getCurrentUser = (): User | null => {
  try {
    const stored = localStorage.getItem(USER_KEY);
    if (stored) {
      currentUser = JSON.parse(stored);
      return currentUser;
    }
  } catch (e) {
    // ignore
  }
  return null;
};

// 保存用户信息
const saveUser = (user: User | null): void => {
  currentUser = user;
  if (user) {
    localStorage.setItem(CLOUDFLARE_API.userKey, JSON.stringify(user));
  } else {
    localStorage.removeItem(CLOUDFLARE_API.userKey);
  }
};

// 获取 Token
const getToken = (): string | null => {
  return localStorage.getItem(CLOUDFLARE_API.tokenKey);
};

// 保存 Token
const saveToken = (token: string): void => {
  localStorage.setItem(CLOUDFLARE_API.tokenKey, token);
};

// 清除 Token
const clearToken = (): void => {
  localStorage.removeItem(CLOUDFLARE_API.tokenKey);
  saveUser(null);
};

// API 请求封装
const apiRequest = async <T>(endpoint: string, options: RequestInit = {}): Promise<T> => {
  const baseUrl = getApiBaseUrl();
  const token = getToken();

  const headers: Record<string, string> = {
    ...((options.headers as Record<string, string>) || {}),
  };

  if (token) {
    headers['Authorization'] = `Bearer ${token}`;
  }

  console.info(`API请求: ${baseUrl}${endpoint}`);

  const response = await fetch(`${baseUrl}${endpoint}`, {
    ...options,
    headers,
  });

  if (response.status === 401) {
    // Token 过期，清除登录状态
    clearToken();
    throw new Error('登录已过期，请重新登录');
  }

  // 尝试解析 JSON 响应
  let data;
  try {
    data = await response.json();
  } catch (e) {
    // 如果不是 JSON 响应，尝试获取文本
    const text = await response.text();
    console.error('API 响应不是 JSON:', text.substring(0, 500));
    throw new Error(`服务器错误: ${response.status} - ${text.substring(0, 100)}`);
  }

  if (!response.ok) {
    throw new Error(data.error || data.message || `请求失败: ${response.status}`);
  }

  return data;
};

// 获取登录 URL
export const getLoginUrl = async (): Promise<{ url: string; state: string; authKey?: string }> => {
  const data = await apiRequest<{ url: string; state: string; authKey?: string }>('/api/auth/login', {
    method: 'GET',
  });
  return data;
};

// 处理 OAuth 回调
export const handleOAuthCallback = async (code: string): Promise<User> => {
  const baseUrl = getApiBaseUrl();
  const token = getToken();

  const headers: Record<string, string> = {
    Accept: 'application/json',
  };

  if (token) {
    headers['Authorization'] = `Bearer ${token}`;
  }

  const response = await fetch(`${baseUrl}/api/auth/callback?code=${code}&format=json`, {
    method: 'GET',
    headers,
  });

  // 尝试解析 JSON 响应
  let data;
  try {
    data = await response.json();
  } catch (e) {
    // 如果不是 JSON 响应，说明后端返回了 HTML（跨域回调页面情况）
    const text = await response.text();
    console.error('回调返回的不是 JSON:', text.substring(0, 500));
    throw new Error('登录失败：无法获取服务器响应');
  }

  if (!response.ok || !data.success || !data.token || !data.user) {
    throw new Error(data.message || '登录失败');
  }

  saveToken(data.token);
  saveUser(data.user);
  return data.user;
};

// 获取当前用户信息
export const fetchCurrentUser = async (): Promise<User | null> => {
  const token = getToken();
  if (!token) return null;

  try {
    const data = await apiRequest<{ user: User | null }>('/api/auth/me', {
      method: 'GET',
    });

    if (data.user) {
      saveUser(data.user);
      return data.user;
    }
  } catch (e) {
    console.error('获取用户信息失败:', e);
  }

  return null;
};

// 登出
export const logout = async (): Promise<void> => {
  try {
    await apiRequest('/api/auth/logout', {
      method: 'POST',
    });
  } catch (e) {
    console.error('登出失败:', e);
  }
  clearToken();
};

// 获取我的项目列表
export const getMyProjects = async (): Promise<Project[]> => {
  const data = await apiRequest<{ success: boolean; projects: Project[] }>('/api/my/projects', {
    method: 'GET',
  });
  return data.projects || [];
};

// 创建项目
export const createProject = async (projectData: {
  name: string;
  description: string;
  version: string;
  tags: string[];
  coverImage?: string;
}): Promise<string> => {
  const data = await apiRequest<{ success: boolean; projectId: string }>('/api/projects', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(projectData),
  });
  return data.projectId;
};

// 上传项目文件
export const uploadProjectFile = async (
  projectId: string,
  file: File,
): Promise<{ downloadUrl: string; fileSize: number }> => {
  const baseUrl = getApiBaseUrl();
  const token = getToken();

  const response = await fetch(`${baseUrl}/api/projects/${projectId}/upload`, {
    method: 'POST',
    headers: {
      Authorization: token ? `Bearer ${token}` : '',
      'Content-Type': file.type || 'application/zip',
    },
    body: file,
  });

  if (!response.ok) {
    const error = await response.json();
    throw new Error(error.error || '上传失败');
  }

  return await response.json();
};

// 上传项目正则文件
export const uploadProjectRegexFile = async (
  projectId: string,
  file: File,
): Promise<{ downloadUrl: string; fileSize: number }> => {
  const baseUrl = getApiBaseUrl();
  const token = getToken();

  const response = await fetch(`${baseUrl}/api/projects/${projectId}/upload-regex`, {
    method: 'POST',
    headers: {
      Authorization: token ? `Bearer ${token}` : '',
      'Content-Type': file.type || 'application/json',
    },
    body: file,
  });

  if (!response.ok) {
    const error = await response.json();
    throw new Error(error.error || '正则文件上传失败');
  }

  return await response.json();
};

// 删除项目
export const deleteProject = async (projectId: string): Promise<void> => {
  await apiRequest(`/api/projects/${projectId}`, {
    method: 'DELETE',
  });
};

// 更新项目信息
export const updateProject = async (projectId: string, updates: Partial<Project>): Promise<void> => {
  await apiRequest(`/api/projects/${projectId}`, {
    method: 'PUT',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(updates),
  });
};

// 获取项目内容 - 通过后端 API 代理下载，解决 CORS 问题
const fetchProjectContent = async (projectId: string): Promise<string> => {
  try {
    const baseUrl = getApiBaseUrl();
    const url = `${baseUrl}/api/files/${projectId}/project-${projectId}.json`;
    console.info(`[CreativeWorkshop] 请求项目内容: ${url}`);

    const res = await fetch(url);
    if (!res.ok) {
      const errorText = await res.text();
      console.error(`[CreativeWorkshop] 获取项目内容失败: ${res.status} - ${errorText}`);
      throw new Error(`无法获取项目内容: ${res.status}`);
    }
    return await res.text();
  } catch (error) {
    console.error(`获取项目 ${projectId} 内容失败:`, error);
    return '获取内容失败';
  }
};

