// 打开上传面板
export const openUploadPanel = async (): Promise<void> => {
  const config = getConfig();
  const targetDoc = window.top?.document || document;

  // 确保全局样式已注入
  injectGlobalStyles(targetDoc);

  // 关闭可能存在的其他模态框
  const existingModal = targetDoc.querySelector('.fate-modal-overlay');
  if (existingModal) {
    existingModal.remove();
  }

  // 创建模态框
  const modalOverlay = targetDoc.createElement('div');
  modalOverlay.className = 'fate-modal-overlay upload-modal';
  Object.assign(modalOverlay.style, {
    position: 'fixed',
    top: '0',
    left: '0',
    width: '100%',
    height: '100%',
    zIndex: '2147483647',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'flex-start',
    paddingTop: '20px',
    paddingBottom: '20px',
    backgroundColor: 'rgba(0,0,0,0.7)',
    backdropFilter: 'blur(4px)',
    boxSizing: 'border-box',
  });

  const modalContent = targetDoc.createElement('div');
  modalContent.className = 'fate-modal-content upload-modal-content';
  Object.assign(modalContent.style, {
    backgroundColor: config.bgColor,
    color: config.textColor,
    borderRadius: '16px',
    padding: '24px',
    width: '90%',
    maxWidth: '800px',
    maxHeight: 'calc(100vh - 40px)',
    overflow: 'auto',
    marginTop: '0',
    marginBottom: '0',
  });

  // 设置 CSS 变量（与 showModal 保持一致）
  const cardDark = adjustColor(config.cardColor, -20);
  const cardLight = adjustColor(config.cardColor, 20);
  modalContent.style.setProperty('--bg-color', config.bgColor);
  modalContent.style.setProperty('--card-base', config.cardColor);
  modalContent.style.setProperty('--card-dark', cardDark);
  modalContent.style.setProperty('--card-light', cardLight);
  modalContent.style.setProperty('--text-color', config.textColor);
  modalContent.style.setProperty('--highlight-color', isLightColor(config.bgColor) ? '#FF6F00' : '#FFD700');

  modalOverlay.appendChild(modalContent);
  targetDoc.body.appendChild(modalOverlay);

  // 渲染内容
  await renderUploadContent(modalContent, modalOverlay);

  // 点击外部关闭
  modalOverlay.onclick = (e: MouseEvent) => {
    if (e.target === modalOverlay) {
      modalOverlay.remove();
    }
  };
};

// 渲染上传内容
const renderUploadContent = async (container: HTMLElement, modalOverlay: HTMLElement): Promise<void> => {
  const config = getConfig();

  // 优先尝试从服务器获取用户信息（如果 localStorage 中有 token）
  const token = getToken();
  if (token) {
    try {
      const user = await fetchCurrentUser();
      if (user) {
        // 服务器验证成功，直接显示已登录界面
        renderLoggedInView(container, modalOverlay, user);
        return;
      }
    } catch (e) {
      console.warn('从服务器获取用户信息失败，可能 token 已过期:', e);
      // token 过期，清除本地存储
      clearToken();
    }
  }

  // 如果没有登录或服务器验证失败，显示登录界面
  const user = getCurrentUser();
  if (!user) {
    // 渲染登录界面
    renderLoginView(container, modalOverlay);
  } else {
    // 渲染已登录界面
    renderLoggedInView(container, modalOverlay, user);
  }
};

// 渲染登录视图
// 监听 OAuth 成功回调的 postMessage
const setupOAuthMessageListener = (container: HTMLElement, modalOverlay: HTMLElement) => {
  const handleMessage = async (event: MessageEvent) => {
    if (event.data.type === 'oauth-success') {
      console.info('收到 OAuth 成功消息:', event.data);
      const { token, user } = event.data;

      try {
        // 保存 token 和用户信息
        localStorage.setItem(CLOUDFLARE_API.tokenKey, token);
        localStorage.setItem(CLOUDFLARE_API.userKey, JSON.stringify(user));

        // 显示成功消息并重新渲染
        toastr.success('登录成功！');
        await renderUploadContent(container, modalOverlay);
      } catch (error) {
        console.error('处理 OAuth 成功回调失败:', error);
        toastr.error('登录成功，但处理用户信息失败');
      }
    } else if (event.data.type === 'oauth-error') {
      console.error('OAuth 错误:', event.data.message);
      toastr.error('登录失败: ' + event.data.message);
    }
  };

  window.addEventListener('message', handleMessage);
  return () => window.removeEventListener('message', handleMessage);
};

