// 格式化文件大小
const formatFileSize = (bytes: number): string => {
  if (bytes === 0) return '0 B';
  const k = 1024;
  const sizes = ['B', 'KB', 'MB', 'GB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
};

// 检查 OAuth 回调并处理登录
export const checkAndHandleOAuthCallback = async (): Promise<boolean> => {
  const url = new URL(window.location.href);

  // 方式1: 检查查询参数中的 code (标准的 OAuth 回调方式)
  const code = url.searchParams.get('code');
  const state = url.searchParams.get('state');

  if (code) {
    try {
      // 清除 URL 中的参数
      window.history.replaceState({}, '', window.location.pathname);

      // 处理 OAuth 回调
      await handleOAuthCallback(code);
      toastr.success('登录成功！');
      return true;
    } catch (e: any) {
      toastr.error('登录失败: ' + e.message);
    }
  }

  // 方式2: 检查 URL hash 中的 token (示例中的方式)
  // 格式: #oauth-success=token 或 #token=xxx
  const hash = window.location.hash;
  if (hash) {
    // 检查 #oauth-success=xxx 格式
    if (hash.startsWith('#oauth-success=')) {
      const token = hash.substring('#oauth-success='.length);
      if (token) {
        try {
          // 尝试从 sessionStorage 获取用户信息
          let userData = null;
          try {
            const userStr = sessionStorage.getItem('cw_userData');
            if (userStr) {
              userData = JSON.parse(userStr);
            }
          } catch (e) {
            console.warn('从 sessionStorage 获取用户信息失败:', e);
          }

          if (userData) {
            // 保存 token 和用户信息
            localStorage.setItem(CLOUDFLARE_API.tokenKey, token);
            localStorage.setItem(CLOUDFLARE_API.userKey, JSON.stringify(userData));

            // 清除 URL hash
            window.history.replaceState({}, '', window.location.pathname);

            toastr.success('登录成功！');
            return true;
          } else {
            // 如果没有用户信息，尝试用 token 获取用户信息
            console.info('使用 token 获取用户信息...');
            const user = await fetchCurrentUser();
            if (user) {
              window.history.replaceState({}, '', window.location.pathname);
              toastr.success('登录成功！');
              return true;
            }
          }
        } catch (e: any) {
          console.error('处理 hash 中的 token 失败:', e);
          toastr.error('登录失败: ' + e.message);
        }
      }
    }

    // 检查 #token=xxx 格式
    if (hash.startsWith('#token=')) {
      const token = hash.substring('#token='.length);
      if (token) {
        try {
          localStorage.setItem(CLOUDFLARE_API.tokenKey, token);

          // 尝试获取用户信息
          const user = await fetchCurrentUser();
          if (user) {
            // 清除 URL hash
            window.history.replaceState({}, '', window.location.pathname);
            toastr.success('登录成功！');
            return true;
          }
        } catch (e: any) {
          console.error('处理 hash 中的 token 失败:', e);
        }
      }
    }
  }

  // 方式3: 检查 localStorage 中是否有之前保存的登录信息
  // (这主要用于处理 postMessage 成功但页面未刷新的情况)
  const savedToken = localStorage.getItem(CLOUDFLARE_API.tokenKey);
  const savedUser = localStorage.getItem(CLOUDFLARE_API.userKey);
  if (savedToken && savedUser) {
    // 验证 token 是否有效
    try {
      const user = await fetchCurrentUser();
      if (user) {
        console.info('从本地存储恢复登录状态');
        return true;
      }
    } catch (e) {
      // token 可能已过期，清除
      localStorage.removeItem(TOKEN_KEY);
      localStorage.removeItem(USER_KEY);
    }
  }

  return false;
};

// 初始化上传面板（检查登录状态）
export const initUploadPanel = async (): Promise<void> => {
  // 检查是否有 OAuth 回调
  const handled = await checkAndHandleOAuthCallback();
  if (handled) {
    // 如果处理了 OAuth 回调，刷新当前用户
    await fetchCurrentUser();
  }
};
