// ==================== 创意工坊脚本 ====================
// 基于原 创意工坊.js 改编为酒馆助手脚本格式

import { getApiBaseUrl } from './config';
import { openUnifiedPanel } from './unifiedPanel';
import { initUploadPanel } from './uploadPanel';

$(function () {
  // ==================== 注册按钮和事件 ====================
  replaceScriptButtons([{ name: '命定创意工坊', visible: true }]);

  eventOn(getButtonEvent('命定创意工坊'), () => {
    openUnifiedPanel();
  });

  // 初始化上传面板（检查 OAuth 回调）
  initUploadPanel();

  console.info('创意工坊脚本已加载');
  console.info('当前 API 地址:', getApiBaseUrl());
});
